@dataclass
class Thinking(AbstractCapability[Any]):
    """启用并配置模型的思考/推理功能。"""

    effort: ThinkingLevel = True
    """思考努力级别。"""

    def get_model_settings(self) -> ModelSettings | None:
        return ModelSettings(thinking=self.effort)

